const items = $input.all();
const wf = $('Ejecutar Workflow').item.json;
const dia = $('Calcular Día Consulta').item.json;

const diaInicio = new Date(dia.dia_inicio);
const diaFin = new Date(dia.dia_fin);
const tipoFiltro = String(dia.tipo_filtro || 'todos').toLowerCase();
const asesorPhone = (wf.telefono_asesor || '').trim();

const eventos = [];

for (const item of items) {
  const ev = item.json;
  const desc = ev.description || '';
  const startRaw = ev.start?.dateTime || ev.start?.date;
  if (!startRaw) continue;
  const startDate = new Date(startRaw);
  if (startDate < diaInicio || startDate > diaFin) continue;

  if (asesorPhone) {
    const m = desc.match(/\[asesor:([^\]]+)\]/);
    const phone = m ? m[1].trim() : '';
    if (phone !== asesorPhone) continue;
  }

  let tipo = 'evento';
  const mTipo = desc.match(/\[tipo:([^\]]+)\]/i);
  if (mTipo) tipo = mTipo[1].trim();
  const tipoLower = tipo.toLowerCase();

  if (tipoFiltro !== 'todos' && tipoLower !== tipoFiltro) continue;

  const horaFormato = ev.start?.dateTime
    ? new Date(ev.start.dateTime).toLocaleTimeString('es-EC', { hour: '2-digit', minute: '2-digit', timeZone: 'America/Guayaquil' })
    : 'Todo el día';
  const fechaFormato = new Date(startRaw).toLocaleDateString('es-EC', { weekday: 'long', day: '2-digit', month: 'long', year: 'numeric', timeZone: 'America/Guayaquil' });

  eventos.push({
    hora: horaFormato,
    fecha: fechaFormato,
    tipo,
    titulo: ev.summary || 'Sin título'
  });
}

if (eventos.length === 0) {
  const etiquetaTipo = tipoFiltro === 'todos' ? 'eventos' : `eventos de tipo ${tipoFiltro}`;
  const fechaTexto = diaInicio.toLocaleDateString('es-EC', { weekday: 'long', day: '2-digit', month: 'long', year: 'numeric', timeZone: 'America/Guayaquil' });
  return [{ json: { resultado: `Para el ${fechaTexto} no tienes ${etiquetaTipo} registrados en tu calendario.` } }];
}

// Ordenar por hora
eventos.sort((a, b) => a.hora.localeCompare(b.hora));

const etiquetaTipo = tipoFiltro === 'todos' ? 'eventos' : `eventos de tipo ${tipoFiltro}`;
const fechaTexto = diaInicio.toLocaleDateString('es-EC', { weekday: 'long', day: '2-digit', month: 'long', year: 'numeric', timeZone: 'America/Guayaquil' });

let texto = `Estos son tus ${etiquetaTipo} para el ${fechaTexto}:\n\n`;
for (const ev of eventos) {
  texto += `- ${ev.hora} - ${ev.tipo}: ${ev.titulo}\n`;
}

return [{ json: { resultado: texto.trim() } }];

const data = $input.first().json;
const datosEvento = $('Preparar Datos Evento1').item.json;
const busy = data.calendars?.primary?.busy ?? [];

const tipo = datosEvento.tipo_evento ?? 'Cita';
const horaBlqIni = datosEvento.hora_bloqueo_inicio ?? null;
const horaBlqFin = datosEvento.hora_bloqueo_fin ?? null;

const toHHMM = iso => new Date(iso).toLocaleTimeString('es-EC', {
  hour: '2-digit', minute: '2-digit', timeZone: 'America/Guayaquil'
});

const toFecha = iso => new Date(iso).toLocaleDateString('es-EC', {
  weekday: 'long', day: '2-digit', month: 'long', year: 'numeric',
  timeZone: 'America/Guayaquil'
});

// Verificar restriccion horaria (solo para Cita y Reunion)
if (horaBlqIni && horaBlqFin && ['Cita', 'Reunion'].includes(tipo)) {
  const fechaEvento = new Date(datosEvento.fecha_inicio);
  const [hIni, mIni] = horaBlqIni.split(':').map(Number);
  const [hFin, mFin] = horaBlqFin.split(':').map(Number);
  const minEvento = fechaEvento.getUTCHours() * 60 + fechaEvento.getUTCMinutes();
  const minIni = hIni * 60 + mIni;
  const minFin = hFin * 60 + mFin;
  if (minEvento >= minIni && minEvento < minFin) {
    return [{
      json: {
        tiene_conflicto: true,
        es_restriccion_horaria: true,
        hora_bloqueo_inicio: horaBlqIni,
        hora_bloqueo_fin: horaBlqFin,
        proximo_disponible_hora: horaBlqFin,
        resultado: '⛔ El horario solicitado (' + toHHMM(datosEvento.fecha_inicio) + ') cae dentro del bloque restringido de ' + horaBlqIni + ' a ' + horaBlqFin + '. Por favor elige un horario fuera de ese rango.'
      }
    }];
  }
}

if (busy.length === 0) {
  return [{ json: { tiene_conflicto: false, es_restriccion_horaria: false } }];
}

// Ordenar periodos ocupados por inicio
const sorted = [...busy].sort((a, b) => new Date(a.start) - new Date(b.start));

// Encontrar el fin mas tardio entre todos los conflictos
let latestEnd = sorted[0].end;
for (const p of sorted) {
  if (new Date(p.end) > new Date(latestEnd)) latestEnd = p.end;
}

return [{
  json: {
    tiene_conflicto: true,
    es_restriccion_horaria: false,
    hora_bloqueo_inicio: horaBlqIni,
    hora_bloqueo_fin: horaBlqFin,
    conflicto_hora_inicio:   toHHMM(sorted[0].start),
    conflicto_hora_fin:      toHHMM(sorted[0].end),
    conflicto_fecha:         toFecha(sorted[0].start),
    proximo_disponible_hora: toHHMM(latestEnd),
    proximo_disponible_iso:  latestEnd,
    total_conflictos: busy.length
  }
}];

